Fix syntax error by properly naming function variables and implement 3-bar confirmation swing detection that validates pattern stability across three consecutive bars.

## Code
```javascript
import React, { useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

const SwingAnalysis = ({ data = [] }) => {
  const swings = useMemo(() => {
    if (!data || data.length < 5) return { highs: [], lows: [] };

    const highs = [];
    const lows = [];

    // Need at least 5 bars: 2 before + pivot + 2 after for 3-bar confirmation
    for (let i = 2; i < data.length - 2; i++) {
      const prev2 = data[i-2];
      const prev1 = data[i-1];
      const current = data[i];
      const next1 = data[i+1];
      const next2 = data[i+2];

      // Swing High: Current high greater than 2 before and 2 after
      const isSwingHigh = 
        current.high > prev2.high &&
        current.high > prev1.high &&
        current.high > next1.high &&
        current.high > next2.high;

      // Swing Low: Current low less than 2 before and 2 after  
      const isSwingLow =
        current.low < prev2.low &&
        current.low < prev1.low &&
        current.low < next1.low &&
        current.low < next2.low;

      if (isSwingHigh) {
        highs.push({
          index: i,
          time: current.time,
          price: current.high,
          confirmed: true
        });
      }

      if (isSwingLow) {
        lows.push({
          index: i,
          time: current.time,
          price: current.low,
          confirmed: true
        });
      }
    }

    return { highs, lows };
  }, [data]);

  const stats = useMemo(() => {
    if (!data.length) return null;

    const prices = data.map(d => d.close);
    const high = Math.max(...data.map(d => d.high));
    const low = Math.min(...data.map(d => d.low));

    return {
      current: prices[prices.length - 1],
      high,
      low,
      range: high - low,
      swingHighCount: swings.highs.length,
      swingLowCount: swings.lows.length
    };
  }, [data, swings]);

  return (
    <Card>
      <CardHeader>
        <CardTitle>Swing Analysis (3-Bar Confirmation)</CardTitle>
      </CardHeader>
      <CardContent>
        {stats && (
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-sm text-muted-foreground">Range</p>
                <p className="text-lg font-semibold">
                  {stats.low.toFixed(2)} - {stats.high.toFixed(2)}
                </p>
              </div>
              <div>
                <p className="text-sm text-muted-foreground">Current</p>
                <p className="text-lg font-semibold">{stats.current.toFixed(2)}</p>
              </div>
              <div>
                <p className="text-sm text-muted-foreground">Swing Highs</p>
                <p className="text-lg font-semibold">{stats.swingHighCount}</p>
              </div>
              <div>
                <p className="text-sm text-muted-foreground">Swing Lows</p>
                <p className="text-lg font-semibold">{stats.swingLowCount}</p>
              </div>
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
};

export default SwingAnalysis;
```

## Why
Fixed variable naming syntax error and implemented true 3-bar confirmation requiring price extremes to exceed two bars on each side, providing more reliable swing identification for institutional-grade analysis.

