    // Swing Low: Current low is less than both neighbors
    if (curr.low < prev.low && curr.low < next.low) {
      swingLows.push({
        index: i,
        price: curr.low,
        time: curr.time
      });
    }
  }

  return { swingHighs, swingLows };
};

// WITH:
const detectSwings = (candles) => {
  const swingHighs = [];
  const swingLows = [];

  for (let i = 2; i < candles.length - 1; i++) {
    const prev2 = candles[i - 2];
    const prev1 = candles[i - 1];
    const curr = candles[i];
    const next = candles[i + 1];

    // Swing High: Current high is greater than prev1, prev2, and next
    if (curr.high > prev1.high && curr.high > prev2.high && curr.high > next.high) {
      swingHighs.push({
        index: i,
        price: curr.high,
        time: curr.time
      });
    }

    // Swing Low: Current low is less than prev1, prev2, and next
    if (curr.low < prev1.low && curr.low < prev2.low && curr.low < next.low) {
      swingLows.push({
        index: i,
        price: curr.low,
        time: curr.time
      });
    }
  }

  return { swingHighs, swingLows };
};
```

## Why
3-bar confirmation requires checking 2 previous bars plus the next bar, eliminating false swings and providing more reliable institutional-grade signals.

