async def _analyze_and_fix(self, error_info: dict) -> Optional[dict]:
    """Analyze stack trace and propose fix"""
    try:
        stack_trace = error_info.get('stack_trace', '')
        error_type = error_info.get('error_type', '')
        file_path = error_info.get('file', '')
        line_no = error_info.get('line', 0)

        # Common error patterns and fixes
        fixes = {
            'ImportError': self._fix_import_error,
            'AttributeError': self._fix_attribute_error,
            'TypeError': self._fix_type_error,
            'KeyError': self._fix_key_error,
            'IndexError': self._fix_index_error,
            'NameError': self._fix_name_error
        }

        fix_handler = fixes.get(error_type)
        if not fix_handler:
            return None

        proposed_fix = await fix_handler(stack_trace, file_path, line_no)
        if proposed_fix:
            return {
                'pr_title': f"Auto-fix {error_type} in {Path(file_path).name}",
                'pr_body': f"Automated fix for {error_type} at line {line_no}",
                'changes': proposed_fix
            }

    except Exception as e:
        self.logger.error(f"Analysis failed: {e}")

    return None

async def _fix_import_error(self, stack_trace: str, file_path: str, line_no: int) -> Optional[dict]:
    """Fix import errors"""
    # Extract missing module from stack trace
    if "No module named" in stack_trace:
        missing = stack_trace.split("No module named")[1].split("'")[1]
        return {
            file_path: {
                'action': 'add_to_requirements',
                'module': missing
            }
        }
    return None

async def _fix_attribute_error(self, stack_trace: str, file_path: str, line_no: int) -> Optional[dict]:
    """Fix attribute errors"""
    if "has no attribute" in stack_trace:
        # Extract object and attribute
        parts = stack_trace.split("'")
        if len(parts) >= 4:
            obj_type = parts[1]
            attr_name = parts[3]

            # Common fixes
            if obj_type == 'dict' and attr_name in ['append', 'push']:
                return {
                    file_path: {
                        'action': 'replace_line',
                        'line': line_no,
                        'fix': f'# Use dict[key] = value instead of dict.{attr_name}()'
                    }
                }
    return None

async def _fix_type_error(self, stack_trace: str, file_path: str, line_no: int) -> Optional[dict]:
    """Fix type errors"""
    if "expected str" in stack_trace:
        return {
            file_path: {
                'action': 'wrap_with_str',
                'line': line_no
            }
        }
    return None

async def _fix_key_error(self, stack_trace: str, file_path: str, line_no: int) -> Optional[dict]:
    """Fix key errors"""
    if "KeyError:" in stack_trace:
        key = stack_trace.split("KeyError:")[1].strip().strip("'\"")
        return {
            file_path: {
                'action': 'add_key_check',
                'line': line_no,
                'key': key
            }
        }
    return None

async def _fix_index_error(self, stack_trace: str, file_path: str, line_no: int) -> Optional[dict]:
    """Fix index errors"""
    return {
        file_path: {
            'action': 'add_bounds_check',
            'line': line_no
        }
    }

async def _fix_name_error(self, stack_trace: str, file_path: str, line_no: int) -> Optional[dict]:
    """Fix name errors"""
    if "is not defined" in stack_trace:
        var_name = stack_trace.split("'")[1]
        return {
            file_path: {
                'action': 'define_variable',
                'line': line_no,
                'variable': var_name
            }
        }
    return None
```

## Why
This implementation analyzes common Python errors from stack traces and proposes specific fixes that can be converted into PRs, enabling true self-healing capability.

