def validate_insights(self, insights: List[Dict]) -> Tuple[bool, str]:
    """Validate if insights are worth implementing"""
    if not insights:
        return False, "No insights provided"

    # Basic validation only
    actionable = sum(1 for i in insights if i.get('actionable', False))
    if actionable == 0:
        return False, "No actionable insights"

