// WITH:
def validate_insights(self, insights: List[Dict]) -> Tuple[bool, str]:
    """Validate if insights are worth implementing"""
    if not insights:
        return False, "No insights provided"

    # Check statistical significance
    min_confidence = 0.65
    min_sample_size = 30

    valid_insights = []
    for insight in insights:
        if not insight.get('actionable', False):
            continue

        confidence = insight.get('confidence', 0)
        evidence = insight.get('evidence', {})
        sample_size = evidence.get('sample_size', 0)

        # For timing insights, check win rates
        if insight['type'] == 'timing':
            win_rates = [evidence.get('morning_win_rate', 0), 
                        evidence.get('afternoon_win_rate', 0)]
            if any(wr > 0.55 for wr in win_rates):
                valid_insights.append(insight)
        # For strike selection, check R:R ratio
        elif insight['type'] == 'strike_selection':
            if sample_size >= min_sample_size and confidence >= min_confidence:
                win_pct = evidence.get('avg_win_pct', 0)
                loss_pct = evidence.get('avg_loss_pct', 1)
                if loss_pct > 0 and (win_pct / loss_pct) > 2.0:
                    valid_insights.append(insight)

    if not valid_insights:
        return False, "No insights meet statistical significance thresholds"

    return True, f"{len(valid_insights)} statistically significant insights ready"
```

## Why
Adds statistical validation to ensure insights have sufficient confidence, sample size, and favorable risk-reward ratios before implementation.

