#!/usr/bin/env python3
"""
Market Structure Analyzer
Analyzes swing highs/lows, trends, and liquidity zones for trading decisions
"""

import argparse
import json
import sys
from pathlib import Path
from typing import Dict, List, Tuple, Optional
import pandas as pd
import numpy as np

def load_market_data(symbol: str, data_path: Path) -> pd.DataFrame:
    """Load market data from CSV format"""
    csv_path = data_path / f"{symbol.replace(':', '_')}_5m.csv"
    if not csv_path.exists():
        return pd.DataFrame()

    df = pd.read_csv(csv_path)
    df['time'] = pd.to_datetime(df['time'])
    return df

def identify_swing_points(df: pd.DataFrame, lookback: int = 5) -> Dict[str, List[int]]:
    """Identify swing highs and lows"""
    highs = []
    lows = []

    for i in range(lookback, len(df) - lookback):
        # Swing High: Higher than lookback bars on both sides
        if all(df['H'].iloc[i] > df['H'].iloc[i-j] for j in range(1, lookback+1)) and \
           all(df['H'].iloc[i] > df['H'].iloc[i+j] for j in range(1, lookback+1)):
            highs.append(i)

        # Swing Low: Lower than lookback bars on both sides
        if all(df['L'].iloc[i] < df['L'].iloc[i-j] for j in range(1, lookback+1)) and \
           all(df['L'].iloc[i] < df['L'].iloc[i+j] for j in range(1, lookback+1)):
            lows.append(i)

    return {'highs': highs, 'lows': lows}

def analyze_trend(df: pd.DataFrame, swings: Dict[str, List[int]]) -> Dict[str, str]:
    """Determine dominant trend based on swing points"""
    if len(swings['highs']) < 2 or len(swings['lows']) < 2:
        return {'trend': 'UNCLEAR', 'strength': 'weak'}

    # Get last 2 highs and lows
    recent_highs = sorted(swings['highs'])[-2:]
    recent_lows = sorted(swings['lows'])[-2:]

    hh = df['H'].iloc[recent_highs[-1]] > df['H'].iloc[recent_highs[-2]]  # Higher High
    ll = df['L'].iloc[recent_lows[-1]] < df['L'].iloc[recent_lows[-2]]   # Lower Low
    hl = df['L'].iloc[recent_lows[-1]] > df['L'].iloc[recent_lows[-2]]   # Higher Low
    lh = df['H'].iloc[recent_highs[-1]] < df['H'].iloc[recent_highs[-2]] # Lower High

    if hh and hl:
        return {'trend': 'BULLISH', 'strength': 'strong'}
    elif ll and lh:
        return {'trend': 'BEARISH', 'strength': 'strong'}
    elif hh and not ll:
        return {'trend': 'BULLISH', 'strength': 'weak'}
    elif ll and not hh:
        return {'trend': 'BEARISH', 'strength': 'weak'}
    else:
        return {'trend': 'RANGING', 'strength': 'neutral'}

def find_liquidity_zones(df: pd.DataFrame, swings: Dict[str, List[int]]) -> List[Dict]:
    """Identify key liquidity zones from swing points"""
    zones = []

    # Major resistance from swing highs
    for idx in swings['highs'][-3:]:  # Last 3 highs
        zones.append({
            'type': 'resistance',
            'level': df['H'].iloc[idx],
            'touches': sum(1 for i in range(idx+1, len(df)) 
                         if abs(df['H'].iloc[i] - df['H'].iloc[idx]) / df['H'].iloc[idx] < 0.001)
        })

    # Major support from swing lows
    for idx in swings['lows'][-3:]:  # Last 3 lows
        zones.append({
            'type': 'support',
            'level': df['L'].iloc[idx],
            'touches': sum(1 for i in range(idx+1, len(df)) 
                         if abs(df['L'].iloc[i] - df['L'].iloc[idx]) / df['L'].iloc[idx] < 0.001)
        })

    return sorted(zones, key=lambda x: x['level'])

def check_structure_break(df: pd.DataFrame, trend: Dict, zones: List[Dict]) -> Dict:
    """Check if structure break is imminent"""
    if df.empty:
        return {'imminent': False, 'type': None}

    current_close = df['C'].iloc[-1]

    # Find nearest support and resistance
    nearest_support = max([z['level'] for z in zones if z['type'] == 'support' and z['level'] < current_close], default=0)
    nearest_resistance = min([z['level'] for z in zones if z['type'] == 'resistance' and z['level'] > current_close], default=float('inf'))

    # Check proximity to key levels
    if trend['trend'] == 'BULLISH' and nearest_resistance < float('inf'):
        if (nearest_resistance - current_close) / current_close < 0.002:  # Within 0.2%
            return {'imminent': True, 'type': 'resistance_test', 'level': nearest_resistance}

    if trend['trend'] == 'BEARISH' and nearest_support > 0:
        if (current_close - nearest_support) / current_close < 0.002:  # Within 0.2%
            return {'imminent': True, 'type': 'support_test', 'level': nearest_support}

    return {'imminent': False, 'type': None}

def get_entry_direction(trend: Dict, structure_break: Dict, df: pd.DataFrame) -> Dict:
    """Determine favored entry direction"""
    if df.empty:
        return {'direction': 'NONE', 'confidence': 0}

    # Recent price action (last 5 bars)
    recent_momentum = (df['C'].iloc[-1] - df['C'].iloc[-5]) / df['C'].iloc[-5]

    if trend['trend'] == 'BULLISH':
        if structure_break['imminent'] and structure_break['type'] == 'resistance_test':
            return {'direction': 'LONG_ON_BREAKOUT', 'confidence': 0.7}
        return {'direction': 'LONG', 'confidence': 0.8}

    elif trend['trend'] == 'BEARISH':
        if structure_break['imminent'] and structure_break['type'] == 'support_test':
            return {'direction': 'SHORT_ON_BREAKDOWN', 'confidence': 0.7}
        return {'direction': 'SHORT', 'confidence': 0.8}

    else:  # RANGING or UNCLEAR
        if abs(recent_momentum) > 0.005:  # 0.5% move
            return {'direction': 'FOLLOW_MOMENTUM', 'confidence': 0.5}
        return {'direction': 'NONE', 'confidence': 0.3}

def analyze_market_structure(symbol: str, data_path: Path = Path("data")) -> Dict:
    """Main analysis function"""
    df = load_market_data(symbol, data_path)

    if df.empty:
        return {
            'symbol': symbol,
            'status': 'NO_DATA',
            'analysis': 'Unable to load market data'
        }

    swings = identify_swing_points(df)
    trend = analyze_trend(df, swings)
    zones = find_liquidity_zones(df, swings)
    structure_break = check_structure_break(df, trend, zones)
    entry = get_entry_direction(trend, structure_break, df)

    return {
