        'entry_direction': entry,
        'current_price': df['C'].iloc[-1],
        'analysis_time': df['time'].iloc[-1].isoformat()
    }

def main():
    parser = argparse.ArgumentParser(description="Analyze market structure for trading decisions")
    parser.add_argument("symbols", nargs="+", help="Symbols to analyze")
    parser.add_argument("--data-path", type=Path, default=Path("data"), help="Path to market data")
