# WITH:
def validate_learning_insights(insights_data: dict) -> dict:
    """Validate learning insights based on statistical significance and quality"""
    insights = insights_data.get("insights", [])

    # Check minimum requirements
    if len(insights) < 2:
        return {"status": "UNCERTAIN", "reason": "Insufficient insights for learning"}

    # Validate each insight
    valid_insights = []
    for insight in insights:
        confidence = insight.get("confidence", 0)
        evidence = insight.get("evidence", {})

        # Strike selection validation
        if insight["type"] == "strike_selection":
            sample_size = evidence.get("sample_size", 0)
            win_pct = evidence.get("avg_win_pct", 0)
            loss_pct = evidence.get("avg_loss_pct", 1)

            if sample_size >= 30 and win_pct/loss_pct > 2.0 and confidence >= 0.7:
                valid_insights.append(insight)

        # Timing validation
        elif insight["type"] == "timing":
            morning_wr = evidence.get("morning_win_rate", 0)
            afternoon_wr = evidence.get("afternoon_win_rate", 0)

            if (morning_wr > 0.6 or afternoon_wr > 0.55) and confidence >= 0.65:
                valid_insights.append(insight)

    # Decision logic
    if len(valid_insights) >= 2:
        avg_confidence = sum(i["confidence"] for i in valid_insights) / len(valid_insights)
        if avg_confidence >= 0.7:
            return {"status": "APPROVE", "reason": "Strong statistical evidence with good R:R ratios"}
        else:
            return {"status": "APPROVE", "reason": "Moderate evidence but actionable patterns"}

    return {"status": "UNCERTAIN", "reason": "Insufficient statistical significance"}
```

## Why
This validates learning insights by checking sample size, risk-reward ratios, and win rates against minimum thresholds for statistical significance.

