            sample_size = evidence.get('sample_size', 0)
            if sample_size < 30:
                concerns.append(f"Strike selection sample size too small ({sample_size})")

        elif insight['type'] == 'timing':
            # Check if win rates are significantly different from random
            win_rates = [evidence.get('morning_win_rate', 0), 
                        evidence.get('afternoon_win_rate', 0)]
            if all(wr < 0.6 for wr in win_rates):
                concerns.append("Timing patterns show marginal improvement over random")

    # Decision logic
    if len(high_confidence) >= 2 and len(concerns) == 0:
        return True, f"APPROVE: {len(high_confidence)} high-confidence insights with solid evidence"
    elif len(concerns) > 0:
        return False, f"REJECT: {'; '.join(concerns)}"
    else:
        return False, "UNCERTAIN: Mixed confidence levels, needs more validation"
```

## Why
This adds statistical rigor by checking confidence thresholds (65%+), sample sizes (30+), and win rate significance (60%+) before approving learning insights.

