// WITH:
const analyzeMarketStructure = (data) => {
  if (!data || data.length < 20) return { trend: 'unknown', entry: null };

  // Find swing highs/lows using 3-bar patterns
  const swings = [];
  for (let i = 1; i < data.length - 1; i++) {
    if (data[i].H > data[i-1].H && data[i].H > data[i+1].H) {
      swings.push({ type: 'high', price: data[i].H, index: i });
    }
    if (data[i].L < data[i-1].L && data[i].L < data[i+1].L) {
      swings.push({ type: 'low', price: data[i].L, index: i });
    }
  }

  // Determine trend from recent swings
  const recentSwings = swings.slice(-4);
  let trend = 'ranging';

  if (recentSwings.length >= 2) {
    const highs = recentSwings.filter(s => s.type === 'high');
    const lows = recentSwings.filter(s => s.type === 'low');

    if (highs.length >= 2 && highs[highs.length-1].price > highs[highs.length-2].price &&
        lows.length >= 2 && lows[lows.length-1].price > lows[lows.length-2].price) {
      trend = 'bullish';
    } else if (highs.length >= 2 && highs[highs.length-1].price < highs[highs.length-2].price &&
               lows.length >= 2 && lows[lows.length-1].price < lows[lows.length-2].price) {
      trend = 'bearish';
    }
  }

  // Check for structure break
  const currentPrice = data[data.length-1].C;
  const lastSwingHigh = swings.filter(s => s.type === 'high').pop();
  const lastSwingLow = swings.filter(s => s.type === 'low').pop();

  let structureBreak = null;
  if (trend === 'bearish' && lastSwingHigh && currentPrice > lastSwingHigh.price) {
    structureBreak = 'bullish_break';
  } else if (trend === 'bullish' && lastSwingLow && currentPrice < lastSwingLow.price) {
    structureBreak = 'bearish_break';
  }

  // Identify liquidity zones
  const liquidityZones = [];
  const priceFrequency = {};
  data.forEach(candle => {
    const zone = Math.round(candle.C / 50) * 50; // 50-point zones
    priceFrequency[zone] = (priceFrequency[zone] || 0) + 1;
  });

  Object.entries(priceFrequency)
    .filter(([_, count]) => count > 3)
    .forEach(([zone, count]) => {
      liquidityZones.push({ price: parseFloat(zone), strength: count });
    });

  // Determine entry direction
  let entry = null;
  if (structureBreak === 'bullish_break') {
    entry = 'long';
  } else if (structureBreak === 'bearish_break') {
    entry = 'short';
  } else if (trend === 'bearish' && !structureBreak) {
    entry = 'short_continuation';
  } else if (trend === 'bullish' && !structureBreak) {
    entry = 'long_continuation';
  }

  return {
    trend,
    swings: recentSwings,
    structureBreak,
    liquidityZones: liquidityZones.sort((a, b) => b.strength - a.strength).slice(0, 3),
    entry,
    currentPrice,
    analysis: {
      dominantTrend: trend,
      liquidityTested: liquidityZones.some(z => Math.abs(z.price - currentPrice) < 25),
      breakImminent: Math.abs(currentPrice - (lastSwingHigh?.price || currentPrice)) < 20 ||
                     Math.abs(currentPrice - (lastSwingLow?.price || currentPrice)) < 20,
      entryDirection: entry
    }
  };
}
