    if (data[i].low < data[i-1].low && data[i].low < data[i+1].low) {
      lows.push({ index: i, price: data[i].low });
    }
  }

  // Determine trend based on recent swing points
  const recentHighs = highs.slice(-3);
  const recentLows = lows.slice(-3);

  let trend = 'neutral';
  if (recentHighs.length >= 2 && recentLows.length >= 2) {
    const higherHighs = recentHighs[recentHighs.length-1].price > recentHighs[recentHighs.length-2].price;
    const higherLows = recentLows[recentLows.length-1].price > recentLows[recentLows.length-2].price;

    if (higherHighs && higherLows) trend = 'bullish';
    else if (!higherHighs && !higherLows) trend = 'bearish';
  }

  // Detect structure break
  const currentPrice = data[data.length-1].close;
  let structureBreak = 'none';

  if (trend === 'bullish' && recentLows.length > 0) {
    const lastSwingLow = recentLows[recentLows.length-1].price;
    if (currentPrice < lastSwingLow) structureBreak = 'bearish';
  } else if (trend === 'bearish' && recentHighs.length > 0) {
    const lastSwingHigh = recentHighs[recentHighs.length-1].price;
    if (currentPrice > lastSwingHigh) structureBreak = 'bullish';
  }

  // Identify liquidity zones (high volume areas)
  const priceFrequency = {};
  data.forEach(candle => {
    const zone = Math.round(candle.close / 10) * 10;
    priceFrequency[zone] = (priceFrequency[zone] || 0) + 1;
  });

  const liquidityZones = [];
  Object.entries(priceFrequency)
    .filter(([_, count]) => count > 3)
    .forEach(([zone, count]) => 
      liquidityZones.push({ price: parseFloat(zone), strength: count })
    );

  return { trend, entry: structureBreak, liquidityZones };
};
```

## Why
Fixed the syntax error by properly closing the forEach loop and ensuring all statements are correctly terminated before the return statement.

