# REPLACE this section:
async def _validate_learning_insights(self, insights: List[Dict]) -> Dict:
    """Validate insights before applying them."""
    # Basic validation
    if not insights:
        return {"valid": False, "reason": "No insights provided"}

# WITH:
async def _validate_learning_insights(self, insights: List[Dict]) -> Dict:
    """Validate insights before applying them."""
    if not insights:
        return {"valid": False, "reason": "No insights provided"}

    # Check statistical significance
    for insight in insights:
        if insight.get("confidence", 0) < 0.65:
            return {"valid": False, "reason": f"Low confidence: {insight.get('confidence')}"}

        # Verify sample size
        evidence = insight.get("evidence", {})
        if evidence.get("sample_size", 0) < 30:
            return {"valid": False, "reason": "Insufficient sample size"}

    return {"valid": True, "actionable_count": sum(1 for i in insights if i.get("actionable"))}
```

```
# ADD this new method after _validate_learning_insights:
async def analyze_learning_decision(self, context: Dict) -> Tuple[str, str]:
    """Analyze learning decision context and return verdict with reasoning."""
    insights = context.get("insights", [])

    # Validate insights
    validation = await self._validate_learning_insights(insights)
    if not validation["valid"]:
        return "REJECT", validation["reason"]

    # Check for actionable insights
    actionable = [i for i in insights if i.get("actionable")]
    if not actionable:
        return "REJECT", "No actionable insights found"

    # Evaluate insight quality
    avg_confidence = sum(i.get("confidence", 0) for i in actionable) / len(actionable)

    if avg_confidence >= 0.7 and validation.get("actionable_count", 0) >= 2:
        return "APPROVE", f"High confidence insights ({avg_confidence:.2f}) with clear action items"
    elif avg_confidence >= 0.65:
        return "UNCERTAIN", f"Moderate confidence ({avg_confidence:.2f}), requires further validation"
    else:
        return "REJECT", f"Confidence too low ({avg_confidence:.2f})"
```

## Why
This adds proper statistical validation and decision logic to evaluate learning insights based on confidence levels, sample sizes, and actionability.

