# REPLACE this function:
def validate_learning_insights(insights: List[Dict]) -> Dict[str, Any]:
    """Validate insights for learning decision."""
    # Basic implementation
    return {"valid": True, "score": 0.5}

# WITH:
def validate_learning_insights(insights: List[Dict]) -> Dict[str, Any]:
    """Validate insights for learning decision."""
    if not insights:
        return {"valid": False, "score": 0, "reason": "No insights provided"}

    total_score = 0
    valid_insights = 0

    for insight in insights:
        # Check required fields
        if not all(k in insight for k in ["type", "confidence", "actionable", "evidence"]):
            continue

        # Validate confidence threshold
        if insight.get("confidence", 0) < 0.65:
            continue

        # Validate evidence quality
        evidence = insight.get("evidence", {})
        if insight["type"] == "strike_selection":
            if evidence.get("sample_size", 0) >= 30 and evidence.get("avg_win_pct", 0) > 5:
                valid_insights += 1
                total_score += insight["confidence"]
        elif insight["type"] == "timing":
            if evidence.get("morning_win_rate", 0) > 0.55 or evidence.get("afternoon_win_rate", 0) > 0.55:
                valid_insights += 1
                total_score += insight["confidence"]

    avg_score = total_score / len(insights) if insights else 0

    return {
        "valid": valid_insights >= 2 and avg_score > 0.65,
        "score": avg_score,
        "valid_count": valid_insights,
        "reason": f"{valid_insights} actionable insights with avg confidence {avg_score:.2f}"
    }
```

## Why
This validates that insights have sufficient statistical significance (sample size >= 30, win rate > 55%, confidence > 65%) before approving learning decisions.

