def validate_learning_decision(self, insights: List[Dict], metadata: Dict) -> ValidationResult:
    """Validate learning decisions based on insights."""
    issues = []
    warnings = []

    # Basic validation
    if not insights:
        return ValidationResult(
            is_valid=False,
            issues=["No insights provided"],
            confidence=0.0
        )

    # Check insight quality
    actionable_count = sum(1 for i in insights if i.get('actionable', False))
    high_confidence_count = sum(1 for i in insights if i.get('confidence', 0) > 0.7)

    if actionable_count == 0:
        issues.append("No actionable insights found")

    if high_confidence_count < len(insights) * 0.5:
        warnings.append("Less than 50% of insights have high confidence")

    # Validate evidence
    for i, insight in enumerate(insights):
        evidence = insight.get('evidence', {})
        if not evidence:
            issues.append(f"Insight {i+1} lacks evidence")
        elif 'sample_size' in evidence and evidence['sample_size'] < 30:
            warnings.append(f"Insight {i+1} has low sample size ({evidence['sample_size']})")

    confidence = self._calculate_learning_confidence(insights, len(issues), len(warnings))

    return ValidationResult(
        is_valid=len(issues) == 0,
        confidence=confidence,
        issues=issues,
        warnings=warnings,
        metadata={
            'actionable_insights': actionable_count,
            'high_confidence_insights': high_confidence_count,
            'total_insights': len(insights)
        }
    )

# WITH:
def validate_learning_decision(self, insights: List[Dict], metadata: Dict) -> ValidationResult:
    """Validate learning decisions based on insights."""
    issues = []
    warnings = []

    # Basic validation
    if not insights:
        return ValidationResult(
            is_valid=False,
            issues=["No insights provided"],
            confidence=0.0
        )

    # Check insight quality
    actionable_count = sum(1 for i in insights if i.get('actionable', False))
    high_confidence_count = sum(1 for i in insights if i.get('confidence', 0) > 0.7)

    if actionable_count == 0:
        issues.append("No actionable insights found")

    if high_confidence_count < len(insights) * 0.5:
        warnings.append("Less than 50% of insights have high confidence")

    # Validate evidence with stricter statistical requirements
    for i, insight in enumerate(insights):
        evidence = insight.get('evidence', {})
        if not evidence:
            issues.append(f"Insight {i+1} lacks evidence")
        elif 'sample_size' in evidence:
            sample_size = evidence['sample_size']
            if sample_size < 30:
                issues.append(f"Insight {i+1} has insufficient sample size ({sample_size} < 30) for statistical significance")
            elif sample_size < 50:
                warnings.append(f"Insight {i+1} has marginal sample size ({sample_size})")

    # Check for conflicting patterns
    if len(insights) > 1:
        # Example: Check if timing insights conflict
        timing_insights = [i for i in insights if i.get('type') == 'timing']
        if len(timing_insights) > 1:
            warnings.append("Multiple timing patterns found - requires prioritization")

    confidence = self._calculate_learning_confidence(insights, len(issues), len(warnings))

    return ValidationResult(
        is_valid=len(issues) == 0,
        confidence=confidence,
        issues=issues,
        warnings=warnings,
        metadata={
            'actionable_insights': actionable_count,
            'high_confidence_insights': high_confidence_count,
            'total_insights': len(insights),
            'recommendation': 'APPROVE' if len(issues) == 0 and confidence > 0.6 else 'REJECT'
