```
// REPLACE this function:
def validate_learning_insights(insights: dict) -> dict:
    """Basic validation of learning insights"""
    return {
        "valid": True,
        "confidence": 0.7,
        "concerns": []
    }

// WITH:
def validate_learning_insights(insights: dict) -> dict:
    """Validate learning insights with statistical and practical checks"""
    concerns = []
    total_confidence = 0

    for insight in insights.get("insights", []):
        # Check sample size significance
        if insight.get("evidence", {}).get("sample_size", 0) < 30:
            concerns.append(f"{insight['type']}: Low sample size ({insight['evidence'].get('sample_size', 0)})")

        # Validate strike selection R:R ratio
        if insight["type"] == "strike_selection":
            evidence = insight["evidence"]
            rr_ratio = evidence.get("avg_win_pct", 0) / max(evidence.get("avg_loss_pct", 1), 0.1)
            if rr_ratio < 2:
                concerns.append("R:R ratio below 2:1 threshold")
            total_confidence += insight["confidence"] * 0.5

        # Validate timing patterns
        elif insight["type"] == "timing":
            evidence = insight["evidence"]
            # Check if win rates are significantly above 50%
            rates = [evidence.get("morning_win_rate", 0), evidence.get("afternoon_win_rate", 0)]
            if all(rate < 0.55 for rate in rates):
                concerns.append("Win rates not significantly above baseline")
            total_confidence += insight["confidence"] * 0.5

    avg_confidence = total_confidence / max(len(insights.get("insights", [])), 1)

    return {
        "valid": len(concerns) == 0,
        "confidence": avg_confidence,
        "concerns": concerns,
        "recommendation": "APPROVE" if len(concerns) == 0 and avg_confidence > 0.65 else "UNCERTAIN"
    }
```

## Why
This adds proper statistical validation for sample sizes, R:R ratios, and win rate significance to make informed learning decisions.

