// REPLACE this validation method:
def validate_learning_decision(self, insights: List[Dict]) -> Tuple[bool, str]:
    """Basic validation without statistical checks"""
    if not insights:
        return False, "No insights provided"
    return True, "Approved"

// WITH:
def validate_learning_decision(self, insights: List[Dict]) -> Tuple[bool, str]:
    """Validate learning insights with statistical significance checks"""
    if not insights:
        return False, "No insights provided"

    reasons = []
    for insight in insights:
        confidence = insight.get('confidence', 0)
        evidence = insight.get('evidence', {})

        if insight['type'] == 'strike_selection':
            # Check R:R ratio significance
            sample_size = evidence.get('sample_size', 0)
            rr_ratio = evidence.get('avg_win_pct', 0) / max(evidence.get('avg_loss_pct', 1), 0.1)

            if sample_size >= 30 and rr_ratio >= 2.5 and confidence >= 0.7:
                reasons.append(f"Strike selection: Strong R:R {rr_ratio:.1f}:1 with n={sample_size}")
            else:
                return False, f"Strike selection: Insufficient evidence (n={sample_size}, R:R={rr_ratio:.1f})"

        elif insight['type'] == 'timing':
            # Check win rate differential
            morning_wr = evidence.get('morning_win_rate', 0)
            midday_wr = evidence.get('midday_win_rate', 0)

            if morning_wr - midday_wr >= 0.15 and confidence >= 0.65:
                reasons.append(f"Timing: Significant edge in optimal windows ({morning_wr:.0%} vs {midday_wr:.0%})")
            else:
                return False, f"Timing: Weak edge ({morning_wr:.0%} vs {midday_wr:.0%})"

    if reasons:
        return True, f"APPROVE: {'; '.join(reasons)}"
    return False, "No actionable insights met criteria"
```

## Why
This validates insights using statistical thresholds for sample size, R:R ratios, and win rate differentials before approving learning decisions.

