"""
Trading Decision Validator
Validates exit decisions based on market conditions and position metrics.
"""

import logging
from typing import Dict, Tuple, Optional
from datetime import datetime, timedelta

logger = logging.getLogger(__name__)

class TradingValidator:
    """Validates trading decisions with market context"""

    def validate_exit_decision(
        self,
        position: Dict,
        market_data: Dict,
        exit_reason: str
    ) -> Tuple[str, float, Optional[Dict]]:
        """
        Validate exit decision based on position and market data.

        Returns:
            (decision, confidence, metadata)
            decision: EXIT_NOW, PARTIAL_EXIT, TRAIL_SL, or HOLD
            confidence: 0.0-1.0
            metadata: Additional context for the decision
        """
        # Extract position metrics
        pnl_percent = position.get('pnl_percent', 0)
        time_in_trade = position.get('time_in_trade', timedelta(0))
        entry_price = position.get('entry_price', 0)
        current_price = position.get('current_price', 0)

        # Analyze market context
        spot_price = market_data.get('spot_price', 0)
        momentum = market_data.get('momentum', 'neutral')
        volume_spike = market_data.get('volume_spike', False)

        # Decision logic for partial_exit_target_hit
        if exit_reason == 'partial_exit_target_hit':
            # With 177% profit in 1 minute, this is exceptional
            if pnl_percent > 150:
                # Extreme profit - take partial immediately
                return "PARTIAL_EXIT", 0.95, {
                    "reason": "Exceptional 177% gain in 1 minute",
                    "exit_percent": 50,
                    "trail_remaining": True
                }
            elif pnl_percent > 100:
                # Strong profit - consider market momentum
                if momentum == 'bullish':
                    return "TRAIL_SL", 0.85, {
                        "reason": "Strong profit with bullish momentum",
                        "trail_percent": 20
                    }
                else:
                    return "PARTIAL_EXIT", 0.90, {
                        "reason": "100%+ profit with non-bullish momentum",
                        "exit_percent": 40
                    }
            elif pnl_percent > 50:
                # Good profit - trail if momentum supports
                if momentum in ['bullish', 'strong_bullish']:
                    return "TRAIL_SL", 0.80, {
                        "reason": "Good profit with supportive momentum",
                        "trail_percent": 15
                    }
                else:
                    return "EXIT_NOW", 0.75, {
                        "reason": "50%+ profit without momentum support"
                    }

        # For this specific case with 177% gain in 1 minute
        if pnl_percent > 150 and time_in_trade.total_seconds() < 120:
            return "PARTIAL_EXIT", 0.95, {
                "reason": "Exceptional gain in minimal time - lock in profits",
                "exit_percent": 50,
                "trail_remaining": True
            }

        # Default to hold if no clear signal
        return "HOLD", 0.50, {"reason": "No clear exit signal"}
```

