def _check_concentration_risk(self, action: Dict) -> bool:
    """Check if action creates concentration risk"""
    if not action.get('orders'):
        return False

    # Get symbol from first order (assuming single symbol per action)
    symbol = action['orders'][0]['symbol']

    # Count existing positions for this symbol
    symbol_positions = sum(1 for pos in self.positions.values() 
                          if pos['symbol'] == symbol)

    # Check concentration limit (max 2 positions per symbol)
    max_positions_per_symbol = 2
    new_orders = len(action['orders'])

    if symbol_positions + new_orders > max_positions_per_symbol:
        logger.warning(f"Concentration risk: {symbol} would have {symbol_positions + new_orders} positions")
        return True

    return False
```

```
