def _check_correlation_risk(self, action: Dict) -> bool:
    """Check if action creates correlation risk"""
    if not action.get('orders'):
        return False

    # Get symbol from action
    symbol = action['orders'][0]['symbol']

    # Count correlated positions (simplified: same underlying index)
    if 'NIFTY' in symbol:
        correlated_count = sum(1 for pos in self.positions.values() 
                             if 'NIFTY' in pos['symbol'])
    elif 'BANK' in symbol:
        correlated_count = sum(1 for pos in self.positions.values() 
                             if 'BANK' in pos['symbol'])
    else:
        correlated_count = 0

    # Max 3 correlated positions
    max_correlated = 3
    new_orders = len(action['orders'])

    if correlated_count + new_orders > max_correlated:
        logger.warning(f"Correlation risk: Would have {correlated_count + new_orders} correlated positions")
        return True

    return False
```

