    if abs(potential_loss) > portfolio['daily_loss_limit']:
        return {
            'approved': False,
            'reason': 'Would exceed daily loss limit',
            'decision': 'REJECT'
        }

    # 2. Position sizing check (max 5% per position)
    position_size = trade_request.get('risk_amount', 0)
    if position_size > portfolio['capital'] * 0.05:
        return {
            'approved': False,
            'reason': 'Position size exceeds 5% limit',
            'decision': 'REDUCE_SIZE'
        }

    # 3. Correlation limit check
    if trade_request.get('correlation_risk') == 'high' and portfolio['open_positions'] >= 3:
        return {
            'approved': False,
            'reason': 'High correlation with existing positions',
            'decision': 'REJECT'
        }

    # 4. Concentration check (max 40% capital usage)
    new_usage = portfolio['used_capital'] + position_size
    if new_usage > portfolio['capital'] * 0.40:
        return {
            'approved': False,
            'reason': 'Would exceed concentration limit',
            'decision': 'REJECT'
        }

    return {
