def check_correlation_limits(self, new_order: Order) -> ValidationResult:
    """Check correlation limits."""
    # Get open positions
    open_positions = self.state.portfolio_tracker.get_open_positions()

    # Check correlation with existing positions
    high_correlation_count = 0
    for pos in open_positions:
        correlation = self._calculate_correlation(
            new_order.symbol, pos.symbol
        )
        if correlation > 0.7:  # High correlation threshold
            high_correlation_count += 1

    # Limit: max 2 highly correlated positions
    if high_correlation_count >= 2:
        return ValidationResult(
            approved=False,
            reason="Too many correlated positions",
            risk_score=0.9
        )

    return ValidationResult(approved=True, risk_score=0.3)

// WITH:
def check_correlation_limits(self, new_order: Order) -> ValidationResult:
    """Check correlation limits."""
    # Get open positions
    open_positions = self.state.portfolio_tracker.get_open_positions()

    # Check correlation with existing positions
    high_correlation_count = 0
    for pos in open_positions:
        correlation = self._calculate_correlation(
            new_order.symbol, pos.symbol
        )
        if correlation > 0.7:  # High correlation threshold
            high_correlation_count += 1

    # With 3 open positions and high correlation risk, reject new orders
    if len(open_positions) >= 3 and high_correlation_count > 0:
        return ValidationResult(
            approved=False,
            reason="Portfolio at capacity with correlated positions",
            risk_score=0.9
        )

    # Limit: max 2 highly correlated positions
    if high_correlation_count >= 2:
        return ValidationResult(
            approved=False,
            reason="Too many correlated positions",
            risk_score=0.9
        )

    return ValidationResult(approved=True, risk_score=0.3)
```

## Why
The current system allows new orders despite having 3 open positions with high correlation risk, which violates prudent risk management principles.

